      "destination": "…",
      "requestsDigest": "sha256:…",
      "freshness": { "…": "…" }
    },
    "decisionId": "…"
  },
  "forwardingProof": {
    "verificationMethod": "…",
    "signature": "…"
  },
  "guardrailProof": {
    "verificationMethod": "…",
    "forwardingProofDigest": "sha256:…",
    "signature": "…"
